const SUPABASE_URL = 'https://faklxfakgzkpkbxfihzh.supabase.co';
const SUPABASE_SERVICE_KEY = 'REDACTED_SUPABASE_KEY';
const SUPABASE_API_KEY = 'REDACTED_SUPABASE_KEY';
const trigger = $('workflow_trigger').first().json;
const userId = trigger.user_id || '';

let recipient_email = trigger.recipient_email;
let bcc_email = trigger.bcc_email;
let story_structure_guidelines = '';
try {
  const rows = await this.helpers.httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/app_config_v2?key=in.(recipient_email,bcc_email,story_structure_guidelines)&select=key,value&user_id=eq.${encodeURIComponent(userId)}`,
    headers: { 'apikey': SUPABASE_API_KEY, 'Authorization': `Bearer ${SUPABASE_API_KEY}` }
  });
  for (const row of rows) {
    if (row.key === 'recipient_email' && !recipient_email) recipient_email = row.value;
    if (row.key === 'bcc_email' && !bcc_email) bcc_email = row.value;
    if (row.key === 'story_structure_guidelines') story_structure_guidelines = row.value;
  }
} catch (e) {
  if (!recipient_email) recipient_email = 'eric@agileadtesting.com';
}


// Load story arcs for write_chapter
let book_arc_prompt = '';
let book_arc_name = '';
let chapter_arc_prompt = '';
let chapter_arc_name = '';
const projectTitle = trigger.project_title || '';
// Try to get book arc from project outline
if (projectTitle) {
  try {
    const projResp = await this.helpers.httpRequest({
      method: 'GET',
      url: SUPABASE_URL + '/rest/v1/writing_projects_v2?title=ilike.*' + encodeURIComponent(projectTitle) + '*&select=outline&limit=1&user_id=eq.' + encodeURIComponent(userId),
      headers: { 'apikey': SUPABASE_API_KEY, 'Authorization': 'Bearer ' + SUPABASE_API_KEY }
    });
    if (Array.isArray(projResp) && projResp.length > 0 && projResp[0].outline) {
      const bookArc = projResp[0].outline.story_arc_name || '';
      if (bookArc) {
        book_arc_name = bookArc;
        try {
          const arcs = await this.helpers.httpRequest({
            method: 'GET',
            url: SUPABASE_URL + '/rest/v1/story_arcs_v2?name=ilike.*' + encodeURIComponent(bookArc) + '*&limit=1',
            headers: { 'apikey': SUPABASE_API_KEY, 'Authorization': 'Bearer ' + SUPABASE_API_KEY }
          });
          if (Array.isArray(arcs) && arcs.length > 0) book_arc_prompt = arcs[0].prompt_text;
        } catch (e) {}
      }
      // Check for chapter-level story arc
      const rawCh = (trigger.chapter_number || '').toString().trim();
      const chNum = /^(prologue|prol|0)$/i.test(rawCh) ? 0 : (/^(epilogue|epil)$/i.test(rawCh) ? -1 : parseInt(rawCh));
      const chapters = projResp[0].outline.chapters || [];
      let thisCh = chapters.find(ch => ch.number === chNum);
      if (!thisCh && chNum === 0) thisCh = chapters.find(ch => /prologue/i.test(ch.title));
      if (thisCh?.chapter_outline?.chapter_story_arc) {
        chapter_arc_name = thisCh.chapter_outline.chapter_story_arc;
        if (chapter_arc_name !== book_arc_name) {
          try {
            const arcs = await this.helpers.httpRequest({
              method: 'GET',
              url: SUPABASE_URL + '/rest/v1/story_arcs_v2?name=ilike.*' + encodeURIComponent(chapter_arc_name) + '*&limit=1',
              headers: { 'apikey': SUPABASE_API_KEY, 'Authorization': 'Bearer ' + SUPABASE_API_KEY }
            });
            if (Array.isArray(arcs) && arcs.length > 0) chapter_arc_prompt = arcs[0].prompt_text;
          } catch (e) {}
        }
      }
    }
  } catch (e) {}
}

return [{ json: { book_arc_prompt, book_arc_name, chapter_arc_prompt, chapter_arc_name, SUPABASE_SERVICE_KEY, SUPABASE_URL, SUPABASE_API_KEY, recipient_email, bcc_email: bcc_email || '', story_structure_guidelines, userId } }];

// Get or create the writing project
const supabaseUrl = $('settings').first().json.SUPABASE_URL;
const apiKey = $('settings').first().json.SUPABASE_API_KEY;
const headers = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json' };
const userId = $('settings').first().json.userId;
const projectTitle = $('workflow_trigger').first().json.project_title;
const genreSlug = $('workflow_trigger').first().json.genre_slug;

// Try to find the project (includes outline)
let project = null;
try {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: supabaseUrl + '/rest/v1/writing_projects_v2?title=ilike.' + encodeURIComponent(projectTitle) + '&user_id=eq.' + encodeURIComponent(userId) + '&limit=1',
    headers: headers
  });
  const projects = Array.isArray(resp) ? resp : [resp];
  if (projects.length > 0 && projects[0]?.id) {
    project = projects[0];
  }
} catch (e) {}

// Create project if not found
if (!project) {
  try {
    const created = await this.helpers.httpRequest({
      method: 'POST',
      url: supabaseUrl + '/rest/v1/writing_projects_v2',
      headers: { ...headers, 'Prefer': 'return=representation' },
      body: { title: projectTitle, genre_slug: genreSlug, project_type: 'book', status: 'in_progress', chapter_count: 0, user_id: userId }
    });
    project = Array.isArray(created) ? created[0] : created;
  } catch (e) {
    // Creation may have failed due to duplicate key — retry lookup before giving up
    try {
      const retry = await this.helpers.httpRequest({
        method: 'GET',
        url: supabaseUrl + '/rest/v1/writing_projects_v2?title=ilike.' + encodeURIComponent(projectTitle) + '&user_id=eq.' + encodeURIComponent(userId) + '&limit=1',
        headers: headers
      });
      const retryProjects = Array.isArray(retry) ? retry : [retry];
      project = (retryProjects.length > 0 && retryProjects[0]?.id) ? retryProjects[0] : { id: null, title: projectTitle };
    } catch (e2) {
      project = { id: null, title: projectTitle };
    }
  }
}

// Fetch story bible entries
let storyBible = [];
if (project?.id) {
  try {
    const bibleResp = await this.helpers.httpRequest({
      method: 'GET',
      url: supabaseUrl + '/rest/v1/story_bible_v2?project_id=eq.' + project.id + '&user_id=eq.' + encodeURIComponent(userId) + '&order=chapter_introduced,entry_type,name',
      headers: headers
    });
    storyBible = Array.isArray(bibleResp) ? bibleResp : [];
  } catch (e) {}
}

// Fetch writing samples
let samplesText = 'No writing samples available.';
try {
  const listResp = await this.helpers.httpRequest({
    method: 'POST',
    url: supabaseUrl + '/storage/v1/object/list/author-content',
    headers: headers,
    body: { prefix: 'writing-samples', limit: 20 }
  });
  const files = (listResp || []).filter(f => f.name && f.name !== '.gitkeep' && f.metadata?.size > 0);
  if (files.length > 0) {
    const samples = [];
    for (const file of files.slice(0, 5)) {
      try {
        const content = await this.helpers.httpRequest({
          method: 'GET',
          url: supabaseUrl + '/storage/v1/object/author-content/writing-samples/' + file.name,
          headers: { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey },
          encoding: 'utf-8',
          json: false
        });
        samples.push(typeof content === 'string' ? content : JSON.stringify(content));
      } catch (e) {}
    }
    if (samples.length > 0) samplesText = samples.join('\n\n');
  }
} catch (e) {}

return [{ json: { project: project, story_bible: storyBible, writing_samples: samplesText, outline: project?.outline || null } }];

const trigger = $('workflow_trigger').first().json;
const genre = $('get_genre_config').first().json;
const genreData = Array.isArray(genre) ? genre[0] : genre;
const research = $('research_topic').first().json.message || '';
const projectData = $('get_project_data').first().json;
const storyBible = projectData.story_bible || [];
const writingSamples = projectData.writing_samples || '';
const bookArcPrompt = $('settings').first().json.book_arc_prompt || '';
const bookArcName = $('settings').first().json.book_arc_name || '';
const chapterArcPrompt = $('settings').first().json.chapter_arc_prompt || '';
const chapterArcName = $('settings').first().json.chapter_arc_name || '';

const wordsPerSection = parseInt(trigger.words_per_section) || 5000;
const storedOutline = projectData.outline;
let outlineText = trigger.outline || '';

if (!outlineText && storedOutline) {
  if (typeof storedOutline === 'object') {
    const parts = [];
    if (storedOutline.premise) parts.push('PREMISE: ' + storedOutline.premise);
    if (storedOutline.themes) parts.push('THEMES: ' + storedOutline.themes.join(', '));
    if (storedOutline.characters) {
      parts.push('CHARACTERS:\n' + storedOutline.characters.map(c => 
        '- ' + c.name + ' (' + c.role + '): ' + c.arc + (c.description ? ' — ' + c.description : '')
      ).join('\n'));
    }
    if (storedOutline.chapters) {
      parts.push('CHAPTER OUTLINE:\n' + storedOutline.chapters.map(ch => 
        'Ch ' + ch.number + ' — ' + ch.title + ': ' + ch.brief + (ch.arc_notes ? ' [Arc: ' + ch.arc_notes + ']' : '')
      ).join('\n'));
    }
    outlineText = parts.join('\n\n');
  } else {
    outlineText = String(storedOutline);
  }
}

const bibleText = storyBible.length > 0
  ? storyBible.map(e => '[' + e.entry_type + '] ' + e.name + ': ' + e.description + ' (ch' + e.chapter_introduced + ')').join('\n')
  : 'No story bible entries yet.';

const rawChapter = (trigger.chapter_number || '').toString().trim();
const isPrologue = /^(prologue|prol|0)$/i.test(rawChapter);
const isEpilogue = /^(epilogue|epil)$/i.test(rawChapter);
const chapterNum = isPrologue ? 0 : (isEpilogue ? -1 : parseInt(rawChapter));
const chapterLabel = isPrologue ? 'Prologue' : (isEpilogue ? 'Epilogue' : 'Chapter ' + chapterNum);

let chapterBrief = trigger.brief || '';
let chapterOutlineText = '';
let subChapters = [];
let chapterOutlineMeta = {};

if (storedOutline && storedOutline.chapters) {
  let thisChapter;
  if (isPrologue) {
    thisChapter = storedOutline.chapters.find(ch => ch.number === 0 || /^prologue$/i.test(String(ch.title)));
  } else if (isEpilogue) {
    thisChapter = storedOutline.chapters.find(ch => /^epilogue$/i.test(String(ch.title)) || ch.number > storedOutline.chapters.filter(c => typeof c.number === 'number').length);
  } else {
    thisChapter = storedOutline.chapters.find(ch => ch.number === chapterNum);
  }
  if (thisChapter) {
    if (!trigger.brief) chapterBrief = thisChapter.brief + (thisChapter.arc_notes ? '\nArc notes: ' + thisChapter.arc_notes : '');
    if (thisChapter.research_topics) {
      // research topics available
    }
  }
  if (thisChapter && thisChapter.chapter_outline && thisChapter.chapter_outline.sub_chapters && thisChapter.chapter_outline.sub_chapters.length > 0) {
    const co = thisChapter.chapter_outline;
    subChapters = co.sub_chapters;
    chapterOutlineMeta = co;
  }
}

// SAFETY GATE
if (subChapters.length === 0) {
  throw new Error('Cannot write ' + chapterLabel + ' — no chapter outline with sub-chapters found. Create one first: "create a chapter outline for ' + chapterLabel.toLowerCase() + ' of ' + trigger.project_title + '"');
}

// Fill in story arc placeholders with actual project data
const protagonist = (storedOutline && storedOutline.characters) ? storedOutline.characters.find(c => c.role === 'Protagonist') : null;
const protagonistDesc = protagonist ? protagonist.name + ' — ' + protagonist.arc : 'See characters in book outline';

function fillArcPlaceholders(arcText) {
  if (!arcText) return '';
  return arcText
    .replace(/\[a full book \/ a single chapter[^\]]*\]/gi, 'a single sub-chapter scene')
    .replace(/\[Book \/ Chapter \/ Short Story[^\]]*\]/gi, 'Sub-chapter scene within a novel chapter')
    .replace(/\[e\.g\., thriller[^\]]*\]/gi, (genreData && genreData.genre_name) || 'fiction')
    .replace(/\[Describe briefly[^\]]*\]/gi, protagonistDesc)
    .replace(/\[What is the core problem[^\]]*\]/gi, (storedOutline && storedOutline.premise) || 'See book outline premise')
    .replace(/\[Where and when[^\]]*\]/gi, 'See sub-chapter setting below')
    .replace(/\[What does the protagonist stand to lose[^\]]*\]/gi, 'See book outline and chapter arc notes')
    .replace(/\[e\.g\., 1,000 words[^\]]*\]/gi, wordsPerSection.toLocaleString() + ' words per sub-chapter')
    .replace(/\[.*?central moral.*?\]/gi, 'See book outline themes')
    .replace(/\[.*?Genre.*?\]/gi, (genreData && genreData.genre_name) || 'fiction')
    .replace(/\[.*?Main character.*?\]/gi, protagonistDesc)
    .replace(/\[.*?Setting.*?\]/gi, 'See sub-chapter setting')
    .replace(/\[.*?Length goal.*?\]/gi, wordsPerSection.toLocaleString() + ' words');
}

const filledChapterArc = fillArcPlaceholders(chapterArcPrompt);
const filledBookArc = fillArcPlaceholders(bookArcPrompt);

// Build shared context (same for all sub-chapters)
const sharedContext = 
  '## Genre Guidelines\n' + (genreData && genreData.writing_guidelines || '') +
  '\n\n## Writing Prime Directive\nWrite like a human, not a machine. Use clear, everyday language and short sentences. Cut cliches. Get to the point. Be genuine. Show, don\'t tell — use concrete details and sensory moments. Stay focused. Keep paragraphs short. Respect the reader\'s intelligence. After drafting, cut anything that doesn\'t move the story forward.' +
  '\n\n## CHARACTER & SCENE DEPTH REQUIREMENTS\n- When a character appears for the FIRST TIME, provide a full physical description: age, build, facial features, clothing, mannerisms, voice quality.\n- Every scene must include LOCAL COLOR: sounds, smells, textures, light quality, weather, background details.\n- Each sub-chapter should be a FULL SCENE with dialogue, internal thought, sensory detail, and character interaction.\n- Write scenes at the pace of lived experience. Describe what characters see, hear, and feel.\n- Do NOT compress or summarize. Write at full narrative depth.' +
  '\n\n## CHAPTER STORY ARC — ' + (chapterOutlineMeta.chapter_story_arc || chapterArcName || bookArcName || '') +
  '\n' + (filledChapterArc || filledBookArc || 'Follow the arc beats from the chapter outline.') +
  '\n\n## Research\n' + research +
  '\n\n## Story Bible (MANDATORY)\n' + bibleText +
  '\n\n## Book Outline (MANDATORY)\n' + outlineText;

// Build the full sub-chapter list for context
const allSubChaptersList = subChapters.map(sc =>
  'Sub-chapter ' + sc.number + ' — ' + sc.title + ': ' + sc.brief
).join('\n');

// Output one item per sub-chapter
const items = subChapters.map((sc, index) => {
  const prevSummaries = subChapters.slice(0, index).map(prev =>
    'Sub-chapter ' + prev.number + ' (' + prev.title + '): ' + prev.brief
  ).join('\n');

  const nextSc = subChapters[index + 1];

  const prompt = 
    'You are a world-class novelist writing Sub-chapter ' + sc.number + ' of ' + subChapters.length + ' for the ' + chapterLabel + ' of "' + trigger.project_title + '", a ' + (genreData && genreData.genre_name || 'fiction') + ' novel.\n\n' +
    '## YOUR ASSIGNMENT — SUB-CHAPTER ' + sc.number + ': ' + sc.title + '\n' +
    'Write ONLY this sub-chapter. Output ONLY narrative prose — no JSON, no metadata, no headers.\n\n' +
    '### What to write\n' +
    'Arc Beat (' + (chapterOutlineMeta.chapter_story_arc || '') + '): ' + (sc.arc_beat || '') + '\n' +
    'Characters: ' + (sc.characters || []).join(', ') + '\n' +
    'Setting: ' + (sc.setting || '') + '\n' +
    'Emotional Tone: ' + (sc.emotional_tone || '') + '\n' +
    'Brief: ' + (sc.brief || '') + '\n' +
    'Book Arc Connection: ' + (sc.connects_to_book_arc || '') + '\n\n' +
    '### CRITICAL RULES\n' +
    '- Write approximately ' + wordsPerSection.toLocaleString() + ' words for this sub-chapter\n' +
    '- Use ONLY the characters listed above — do NOT introduce new characters\n' +
    '- Set the scene in the setting specified above\n' +
    '- Match the emotional tone specified\n' +
    '- Follow the arc beat for this sub-chapter\n' +
    (index === 0 ? '- This is the OPENING sub-chapter. Establish the scene, introduce the character with full physical description, set the tone.\n' : '') +
    (index === subChapters.length - 1 ? '- This is the FINAL sub-chapter. Provide closure for the chapter while creating a hook for the next chapter.\n' : '') +
    '\n### Full chapter structure (for context — write ONLY sub-chapter ' + sc.number + ')\n' +
    allSubChaptersList + '\n' +
    (prevSummaries ? '\n### Previous sub-chapters (already written — maintain continuity)\n' + prevSummaries + '\n' : '') +
    (nextSc ? '\n### Next sub-chapter (for transition)\n' + nextSc.title + ': ' + nextSc.brief + '\n' : '') +
    '\n' + sharedContext;

  return {
    json: {
      prompt,
      sub_chapter_number: sc.number,
      sub_chapter_title: sc.title,
      project_id: projectData.project && projectData.project.id,
      total_sub_chapters: subChapters.length,
      chapter_label: chapterLabel,
      chapter_outline_meta: chapterOutlineMeta
    }
  };
});

return items;

// Update story bible with new entries from this chapter
const supabaseUrl = $('settings').first().json.SUPABASE_URL;
const apiKey = $('settings').first().json.SUPABASE_API_KEY;
const headers = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json' };
const userId = $('settings').first().json.userId;
const projectId = $('build_sub_chapter_prompts').first().json.project_id;
const rawCh = ($('workflow_trigger').first().json.chapter_number || '').toString().trim();
const isProl = /^(prologue|prol|0)$/i.test(rawCh);
const isEpil = /^(epilogue|epil)$/i.test(rawCh);
const chapterNum = isProl ? 0 : (isEpil ? 999 : (parseInt(rawCh) || 0));
const chapterLabel = isProl ? 'Prologue' : (isEpil ? 'Epilogue' : rawCh);
const output = $input.first().json.output || {};
const newEntries = output.new_story_bible_entries || [];

// Insert new story bible entries
if (newEntries.length > 0 && projectId) {
  try {
    const entries = newEntries.map(e => ({
      entry_type: e.entry_type,
      name: e.name,
      description: e.description,
      project_id: projectId,
      chapter_introduced: chapterNum,
      last_chapter_seen: chapterNum,
      user_id: userId
    }));
    await this.helpers.httpRequest({
      method: 'POST',
      url: supabaseUrl + '/rest/v1/story_bible_v2',
      headers: headers,
      body: entries
    });
  } catch (e) {}
}

// Update project chapter count
if (projectId) {
  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: supabaseUrl + '/rest/v1/writing_projects_v2?id=eq.' + projectId + '&user_id=eq.' + encodeURIComponent(userId),
      headers: headers,
      body: Object.assign({ status: 'in_progress', updated_at: new Date().toISOString() }, (!isProl && !isEpil) ? { chapter_count: chapterNum } : {})
    });
  } catch (e) {}
}

return [{ json: { output: output, project_id: projectId } }];

