  if (storedOutline.themes) parts.push('THEMES: ' + storedOutline.themes.join(', '));
  if (storedOutline.story_arc_name) parts.push('BOOK STORY ARC: ' + storedOutline.story_arc_name);
  if (storedOutline.characters) {
    parts.push('CHARACTERS:\n' + storedOutline.characters.map(c =>
      '- ' + c.name + ' (' + c.role + '): ' + c.arc
    ).join('\n'));
  }
  if (storedOutline.chapters) {
    parts.push('CHAPTER OUTLINE:\n' + storedOutline.chapters.map(ch =>
      'Ch ' + ch.number + ' — ' + ch.title + ': ' + ch.brief + (ch.arc_notes ? ' [Arc: ' + ch.arc_notes + ']' : '')
    ).join('\n'));
  }
  bookOutlineText = parts.join('\n\n');
}

// Get chapter outline (sub-chapters)
const rawCh = (trigger.chapter_number || '').toString().trim();
const isProl = /^(prologue|prol|0)$/i.test(rawCh);
const isEpil = /^(epilogue|epil)$/i.test(rawCh);
const chNum = isProl ? 0 : (isEpil ? -1 : parseInt(rawCh));
let chapterOutlineText = 'No chapter outline found.';
let thisChapter = null;
if (storedOutline?.chapters) {
  if (isProl) thisChapter = storedOutline.chapters.find(ch => ch.number === 0 || /prologue/i.test(ch.title));
  else if (isEpil) thisChapter = storedOutline.chapters.find(ch => /epilogue/i.test(ch.title));
  else thisChapter = storedOutline.chapters.find(ch => ch.number === chNum);
}
if (thisChapter?.chapter_outline?.sub_chapters) {
  const co = thisChapter.chapter_outline;
  chapterOutlineText = 'Chapter Story Arc: ' + (co.chapter_story_arc || 'Same as book') + '\n' +
    'Book Arc Beat: ' + (co.book_arc_beat || '') + '\n' +
    co.sub_chapters.map(sc =>
      'Sub-chapter ' + sc.number + ': ' + sc.title + '\n' +
      '  Brief: ' + sc.brief + '\n' +
      '  Characters: ' + (sc.characters || []).join(', ')
    ).join('\n\n');
}

// Load story arc prompts for validation
const bookArcName = storedOutline?.story_arc_name || '';
const bookArcPrompt = s.book_arc_prompt || '';
let chapterArcName = '';
let chapterArcPrompt = '';
if (thisChapter?.chapter_outline) {
  chapterArcName = thisChapter.chapter_outline.chapter_story_arc || bookArcName;
  chapterArcPrompt = s.chapter_arc_prompt || '';
}

// Build story arc context for Q/A
let storyArcContext = '';
if (bookArcName) {
  storyArcContext += '\nBOOK STORY ARC: ' + bookArcName;
  if (bookArcPrompt) {
    // Extract just the key structural rules (first 2000 chars of arc prompt)
    const arcRules = bookArcPrompt.substring(0, 2000);
    storyArcContext += '\nKey structural requirements:\n' + arcRules;
  }
}
if (chapterArcName && chapterArcName !== bookArcName) {
  storyArcContext += '\n\nCHAPTER STORY ARC: ' + chapterArcName;
  if (chapterArcPrompt) {
    const chArcRules = chapterArcPrompt.substring(0, 2000);
    storyArcContext += '\nKey structural requirements:\n' + chArcRules;
  }
}

// Build Q/A prompt
const qaPrompt = `You are a story consistency auditor. A chapter has just been written. Your job is to verify it against the book outline, chapter outline, and the story arc frameworks being used. Be thorough but fair.

## BOOK OUTLINE
${bookOutlineText}

## STORY ARC FRAMEWORKS
${storyArcContext || 'No story arc specified.'}

## CHAPTER OUTLINE (SUB-CHAPTERS)
${chapterOutlineText}

## CHAPTER JUST WRITTEN
Title: ${chapterTitle}
${chapterText.substring(0, 12000)}${chapterText.length > 12000 ? '\n...[truncated for review]' : ''}

## VALIDATION CHECKLIST
For each item, respond PASS or FAIL with a brief explanation:

1. **Character Consistency**: Do all character names in the written chapter match the book outline exactly? Are there any invented, renamed, or missing characters?
2. **Book Arc Advancement**: Does this chapter advance the book's story arc as described in the book outline's arc_notes for this chapter?
3. **Chapter Outline Adherence**: Does the written chapter follow the sub-chapter sequence from the chapter outline? Are all sub-chapters represented?
4. **Plot Consistency**: Does the chapter contradict any established plot points, events, or character relationships from the book outline?
5. **Theme Alignment**: Does the chapter support the book's stated themes, or does it drift toward unrelated themes?
6. **Story Drift Risk**: Is there any subtle change in the story's direction that could take the narrative off its intended path? (e.g., a character making a decision that contradicts their arc, a plot thread introduced that wasn't in the outline)
7. **Book Story Arc Compliance**: Does this chapter fulfill its assigned role in the BOOK's story arc (${bookArcName || 'not specified'})? Check: does the chapter hit the structural beat assigned to it in the book outline's arc_notes? Does the emotional progression match what the arc framework requires at this position in the story?
8. **Chapter Story Arc Compliance**: If this chapter uses its own story arc (${chapterArcName || 'same as book'}), does the internal structure of the chapter follow that arc's framework? Are the sub-chapters organized according to the arc's beats/stages? Does the chapter's internal emotional progression follow the arc's prescribed pattern?
9. **Arc Contradiction Check**: Does anything in this chapter CONTRADICT the story arc's rules? For example: if the book arc says this chapter should be the "Ordeal" (Hero's Journey), does the chapter actually deliver a crisis/ordeal? If the chapter arc is Kishōtenketsu, is there forced conflict where the arc says there should be contrast? Flag any structural violations.

## OUTPUT FORMAT
Return JSON with:
- overall_status: "PASS" or "NEEDS_REVIEW" (use NEEDS_REVIEW if ANY item is FAIL)
- checks: array of {name, status ("PASS" or "FAIL"), detail}
- summary: one paragraph summarizing the chapter's consistency
- concerns: array of strings listing any specific issues (empty if all PASS)`;

// Call Claude for Q/A validation

return [{ json: { qaPrompt } }];

const qaText = $input.first().json.text || $input.first().json.output?.text || '';

let qaResult;
try {
  const jsonMatch = qaText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    qaResult = JSON.parse(jsonMatch[0]);
  } else {
    qaResult = { overall_status: 'UNKNOWN', summary: qaText.substring(0, 500), checks: [], concerns: ['Could not parse Q/A response as JSON'] };
  }
} catch (e) {
  qaResult = { overall_status: 'UNKNOWN', summary: qaText.substring(0, 500), checks: [], concerns: ['JSON parse error: ' + e.message] };
}

const statusColor = qaResult.overall_status === 'PASS' ? '#2d8a4e' : (qaResult.overall_status === 'NEEDS_REVIEW' ? '#c9302c' : '#888');

let checksHtml = '';
if (qaResult.checks && qaResult.checks.length > 0) {
  checksHtml = qaResult.checks.map(c =>
    '<tr><td style="padding:4px 8px;">' + (c.status === 'PASS' ? '✅' : '❌') + ' ' + c.name + '</td><td style="padding:4px 8px;">' + c.detail + '</td></tr>'
  ).join('');
}

const qaHtml = '<div style="border:2px solid ' + statusColor + '; border-radius:8px; padding:16px; margin-top:24px; font-family:sans-serif;">' +
  '<h2 style="color:' + statusColor + '; margin-top:0;">Story Consistency Report: ' + qaResult.overall_status + '</h2>' +
  '<p>' + (qaResult.summary || '') + '</p>' +
  (checksHtml ? '<table style="width:100%; border-collapse:collapse; margin:12px 0;"><tr style="background:#f5f5f5;"><th style="text-align:left; padding:4px 8px;">Check</th><th style="text-align:left; padding:4px 8px;">Detail</th></tr>' + checksHtml + '</table>' : '') +
  (qaResult.concerns && qaResult.concerns.length > 0 ? '<h3 style="color:#c9302c;">Concerns:</h3><ul>' + qaResult.concerns.map(c => '<li>' + c + '</li>').join('') + '</ul>' : '') +
  '</div>';

return [{ json: { qa_report: qaResult, qa_html: qaHtml, qa_status: qaResult.overall_status || 'UNKNOWN' } }];

const items = $input.all();
const firstItem = $('build_sub_chapter_prompts').first().json;
const chapterLabel = firstItem.chapter_label || 'Chapter';
const meta = firstItem.chapter_outline_meta || {};

// Collect all sub-chapter texts
const subChapterTexts = items.map((item, i) => {
  const text = item.json.text || item.json.output || '';
  return text;
});

// Concatenate with scene breaks
const fullText = subChapterTexts.join('\n\n---\n\n');
const wordCount = fullText.split(/\s+/).length;

// Build chapter summary from meta
const summary = meta.chapter_summary || 'Chapter written with ' + items.length + ' sub-chapters.';

return [{ json: {
  output: {
    chapter_title: meta.chapter_title || chapterLabel,
    chapter_text: fullText,
    word_count: wordCount,
    chapter_summary: summary,
    next_chapter_notes: 'Continue to the next chapter per the book outline.',
    new_story_bible_entries: []
  }
} }];

// Rate limit delay — wait 5 seconds between sub-chapter API calls
const itemIndex = $input.first().json.sub_chapter_number || 0;
if (itemIndex > 1) {
  await new Promise(resolve => setTimeout(resolve, 5000));
}
return $input.all();
